import{_ as t,o as a,c as o,a2 as n}from"./chunks/framework.BWHo9ZVz.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"appendices/appendix-a-the-go-proverbs.md","filePath":"appendices/appendix-a-the-go-proverbs.md"}'),r={name:"appendices/appendix-a-the-go-proverbs.md"};function i(s,e,l,u,c,d){return a(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="appendix-a-the-go-proverbs" tabindex="-1">Appendix A: The Go Proverbs <a class="header-anchor" href="#appendix-a-the-go-proverbs" aria-label="Permalink to &quot;Appendix A: The Go Proverbs&quot;">​</a></h2><p>Rob Pike&#39;s <strong>Go Proverbs</strong> outline the design philosophy and programming style of the Go language. Below is the complete list of proverbs with detailed explanations based on the context of Matt Holliday&#39;s lectures.</p><h3 id="_1-don-t-communicate-by-sharing-memory-share-memory-by-communicating" tabindex="-1">1. &quot;Don&#39;t communicate by sharing memory; share memory by communicating.&quot; <a class="header-anchor" href="#_1-don-t-communicate-by-sharing-memory-share-memory-by-communicating" aria-label="Permalink to &quot;1. &quot;Don&#39;t communicate by sharing memory; share memory by communicating.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 22, 23, 26.</li><li><strong>Meaning:</strong> Instead of using shared variables protected by locks (mutexes) to pass data between execution threads (which easily leads to race conditions, deadlocks, and complexity), use channels to pass ownership of data between concurrent goroutines. Communication is the mechanism for synchronization.</li></ul><h3 id="_2-concurrency-is-not-parallelism" tabindex="-1">2. &quot;Concurrency is not parallelism.&quot; <a class="header-anchor" href="#_2-concurrency-is-not-parallelism" aria-label="Permalink to &quot;2. &quot;Concurrency is not parallelism.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 22.</li><li><strong>Meaning:</strong> Concurrency is about <em>structure</em>—decomposing a program into independently executing processes. Parallelism is about <em>execution</em>—the simultaneous execution of multiple things on multiple physical CPU cores. A well-structured concurrent program can run in parallel on a multi-core machine, but it also runs correctly on a single-core CPU.</li></ul><h3 id="_3-channels-marshal-mutexes-serialize" tabindex="-1">3. &quot;Channels marshal; mutexes serialize.&quot; <a class="header-anchor" href="#_3-channels-marshal-mutexes-serialize" aria-label="Permalink to &quot;3. &quot;Channels marshal; mutexes serialize.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 28.</li><li><strong>Meaning:</strong> Channels are ideal for passing ownership of data, communicating status updates, and orchestrating workflows (marshaling). Mutexes (mutual exclusion locks) are ideal for protecting shared mutable state inside a single struct or memory area by ensuring only one goroutine can read/write to it at a time (serialization). Use the right tool for the job.</li></ul><h3 id="_4-the-bigger-the-interface-the-weaker-the-abstraction" tabindex="-1">4. &quot;The bigger the interface, the weaker the abstraction.&quot; <a class="header-anchor" href="#_4-the-bigger-the-interface-the-weaker-the-abstraction" aria-label="Permalink to &quot;4. &quot;The bigger the interface, the weaker the abstraction.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 18, 20.</li><li><strong>Meaning:</strong> Interfaces with many methods specify too many implementation details, limiting their reusable abstractions. Tiny interfaces (like <code>io.Reader</code> and <code>io.Writer</code> with exactly one method each) are powerful because almost any data source or sink can implement them.</li></ul><h3 id="_5-make-the-zero-value-useful" tabindex="-1">5. &quot;Make the zero value useful.&quot; <a class="header-anchor" href="#_5-make-the-zero-value-useful" aria-label="Permalink to &quot;5. &quot;Make the zero value useful.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 3, 12, 28.</li><li><strong>Meaning:</strong> Go variables are automatically initialized to their &quot;zero value&quot; (e.g., <code>0</code> for numeric types, <code>&quot;&quot;</code> for strings, <code>false</code> for booleans, <code>nil</code> for pointers/slices/maps). Designing structs so that their default zero state is fully functional and ready to use without explicit initialization (like <code>sync.Mutex</code> or <code>bytes.Buffer</code>) makes code cleaner and safer.</li></ul><h3 id="_6-interface-says-nothing" tabindex="-1">6. &quot;interface{} says nothing.&quot; <a class="header-anchor" href="#_6-interface-says-nothing" aria-label="Permalink to &quot;6. &quot;interface{} says nothing.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 20, 33.</li><li><strong>Meaning:</strong> The empty interface <code>interface{}</code> (aliased as <code>any</code> in modern Go) specifies zero methods, which means it provides no static information about the underlying type. Overusing it defeats Go&#39;s strong static type-checking, forcing run-time type assertions and increasing the likelihood of bugs.</li></ul><h3 id="_7-gofmt-s-style-is-no-one-s-favorite-yet-gofmt-is-everyone-s-favorite" tabindex="-1">7. &quot;Gofmt&#39;s style is no one&#39;s favorite, yet gofmt is everyone&#39;s favorite.&quot; <a class="header-anchor" href="#_7-gofmt-s-style-is-no-one-s-favorite-yet-gofmt-is-everyone-s-favorite" aria-label="Permalink to &quot;7. &quot;Gofmt&#39;s style is no one&#39;s favorite, yet gofmt is everyone&#39;s favorite.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 37.</li><li><strong>Meaning:</strong> The <code>gofmt</code> tool formats Go code according to a standard style. While individual developers may disagree with specific formatting choices, having a single standard eliminates bikeshedding and makes all Go code bases instantly recognizable and readable to any developer.</li></ul><h3 id="_8-a-little-copying-is-better-than-a-little-dependency" tabindex="-1">8. &quot;A little copying is better than a little dependency.&quot; <a class="header-anchor" href="#_8-a-little-copying-is-better-than-a-little-dependency" aria-label="Permalink to &quot;8. &quot;A little copying is better than a little dependency.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 40.</li><li><strong>Meaning:</strong> Importing third-party packages to use a single simple function introduces maintenance, compatibility, and security risks. If a function is small and easily written, it is often better to copy/paste it into your project than to pull in a large external dependency.</li></ul><h3 id="_9-syscall-must-always-be-guarded-with-build-tags" tabindex="-1">9. &quot;Syscall must always be guarded with build tags.&quot; <a class="header-anchor" href="#_9-syscall-must-always-be-guarded-with-build-tags" aria-label="Permalink to &quot;9. &quot;Syscall must always be guarded with build tags.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 31, 41.</li><li><strong>Meaning:</strong> Direct operating system calls (<code>syscall</code> package) are platform-dependent. To maintain cross-compilation support, these files must be isolated using compiler build tags (e.g., <code>//go:build linux</code>) so they only compile on their target platforms.</li></ul><h3 id="_10-cgo-must-always-be-guarded-with-build-tags" tabindex="-1">10. &quot;Cgo must always be guarded with build tags.&quot; <a class="header-anchor" href="#_10-cgo-must-always-be-guarded-with-build-tags" aria-label="Permalink to &quot;10. &quot;Cgo must always be guarded with build tags.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 31, 41.</li><li><strong>Meaning:</strong> Cgo allows Go to call C library routines, but it breaks cross-compilation and degrades build performance. Guard files using Cgo with build tags so that pure-Go fallbacks can be compiled on other architectures.</li></ul><h3 id="_11-cgo-is-not-go" tabindex="-1">11. &quot;Cgo is not Go.&quot; <a class="header-anchor" href="#_11-cgo-is-not-go" aria-label="Permalink to &quot;11. &quot;Cgo is not Go.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 41.</li><li><strong>Meaning:</strong> Cgo bypasses the safety guarantees of Go&#39;s memory model, garbage collection, and goroutine scheduling. Debugging Cgo is complex, build times increase, and binaries can no longer compile statically by default. Avoid Cgo unless absolutely necessary.</li></ul><h3 id="_12-with-the-unsafe-package-there-are-no-guarantees" tabindex="-1">12. &quot;With the unsafe package there are no guarantees.&quot; <a class="header-anchor" href="#_12-with-the-unsafe-package-there-are-no-guarantees" aria-label="Permalink to &quot;12. &quot;With the unsafe package there are no guarantees.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 33, 34.</li><li><strong>Meaning:</strong> The <code>unsafe</code> package allows developers to bypass Go&#39;s type system and read/write raw memory addresses. Code utilizing <code>unsafe</code> is not guaranteed to be compatible across compiler updates or different CPU architectures.</li></ul><h3 id="_13-clear-is-better-than-clever" tabindex="-1">13. &quot;Clear is better than clever.&quot; <a class="header-anchor" href="#_13-clear-is-better-than-clever" aria-label="Permalink to &quot;13. &quot;Clear is better than clever.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 43.</li><li><strong>Meaning:</strong> Maintainable software engineering requires code to be obvious and readable. Clever one-liners or highly complex abstractions are hard to debug, difficult to modify, and slow down team collaboration.</li></ul><h3 id="_14-reflection-is-never-clear" tabindex="-1">14. &quot;Reflection is never clear.&quot; <a class="header-anchor" href="#_14-reflection-is-never-clear" aria-label="Permalink to &quot;14. &quot;Reflection is never clear.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 33.</li><li><strong>Meaning:</strong> Reflection allows run-time inspection of types and values, but the resulting code is slow, verbose, and difficult to comprehend. If a problem can be solved with static interfaces, avoid using reflection.</li></ul><h3 id="_15-errors-are-values" tabindex="-1">15. &quot;Errors are values.&quot; <a class="header-anchor" href="#_15-errors-are-values" aria-label="Permalink to &quot;15. &quot;Errors are values.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 32.</li><li><strong>Meaning:</strong> Go does not have run-time exceptions. Instead, errors are ordinary values returned as the final parameter of a function. Because errors are values, they can be inspected, compared, wrapped, and processed using standard language features.</li></ul><h3 id="_16-don-t-just-check-errors-handle-them-gracefully" tabindex="-1">16. &quot;Don&#39;t just check errors, handle them gracefully.&quot; <a class="header-anchor" href="#_16-don-t-just-check-errors-handle-them-gracefully" aria-label="Permalink to &quot;16. &quot;Don&#39;t just check errors, handle them gracefully.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 32.</li><li><strong>Meaning:</strong> Simply propagating an error up the call stack with <code>if err != nil { return err }</code> is insufficient. A good program adds context to errors (wrapping them), logs them appropriately, fallback to safe defaults, or retries the operation where sensible.</li></ul><h3 id="_17-design-the-architecture-don-t-design-the-code" tabindex="-1">17. &quot;Design the architecture, don&#39;t design the code.&quot; <a class="header-anchor" href="#_17-design-the-architecture-don-t-design-the-code" aria-label="Permalink to &quot;17. &quot;Design the architecture, don&#39;t design the code.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 41, 43.</li><li><strong>Meaning:</strong> Focus on the relationships between components, packages, boundaries, and data flows. Designing complex internal code patterns before establishing a solid architectural boundary leads to rigid, tightly coupled systems.</li></ul><h3 id="_18-documentation-is-for-users-comments-are-for-maintainers" tabindex="-1">18. &quot;Documentation is for users; comments are for maintainers.&quot; <a class="header-anchor" href="#_18-documentation-is-for-users-comments-are-for-maintainers" aria-label="Permalink to &quot;18. &quot;Documentation is for users; comments are for maintainers.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 41.</li><li><strong>Meaning:</strong> Exported API documentation (e.g. package godocs) should explain <em>how</em> to use the package. In-code comments should explain <em>why</em> certain non-obvious decisions or algorithms were written, assisting developers who maintain the source code.</li></ul><h3 id="_19-don-t-panic" tabindex="-1">19. &quot;Don&#39;t panic.&quot; <a class="header-anchor" href="#_19-don-t-panic" aria-label="Permalink to &quot;19. &quot;Don&#39;t panic.&quot;&quot;">​</a></h3><ul><li><strong>Context:</strong> Class 8, 32.</li><li><strong>Meaning:</strong> The <code>panic</code> mechanism crashes the program. Panicking should only be used for unrecoverable startup configuration errors or programmer bugs (like array out of bounds). Real-world runtime errors (like database connection issues) must be returned as standard <code>error</code> values.</li></ul><hr>',41)])])}const m=t(r,[["render",i]]);export{g as __pageData,m as default};
